1	import {
2	  InvalidResponseDataError,
3	  LanguageModelV3,
4	  LanguageModelV3CallOptions,
5	  LanguageModelV3Content,
6	  LanguageModelV3FinishReason,
7	  LanguageModelV3GenerateResult,
8	  LanguageModelV3StreamPart,
9	  LanguageModelV3StreamResult,
10	  SharedV3ProviderMetadata,
11	  SharedV3Warning,
12	} from '@ai-sdk/provider';
13	import {
14	  FetchFunction,
15	  ParseResult,
16	  combineHeaders,
17	  createEventSourceResponseHandler,
18	  createJsonResponseHandler,
19	  generateId,
20	  isParsableJson,
21	  parseProviderOptions,
22	  postJsonToApi,
23	} from '@ai-sdk/provider-utils';
24	import { openaiFailedResponseHandler } from '../openai-error';
25	import { getOpenAILanguageModelCapabilities } from '../openai-language-model-capabilities';
26	import {
27	  OpenAIChatUsage,
28	  convertOpenAIChatUsage,
29	} from './convert-openai-chat-usage';
30	import { convertToOpenAIChatMessages } from './convert-to-openai-chat-messages';
31	import { getResponseMetadata } from './get-response-metadata';
32	import { mapOpenAIFinishReason } from './map-openai-finish-reason';
33	import {
34	  OpenAIChatChunk,
35	  openaiChatChunkSchema,
36	  openaiChatResponseSchema,
37	} from './openai-chat-api';
38	import {
39	  OpenAIChatModelId,
40	  openaiLanguageModelChatOptions,
41	} from './openai-chat-options';
42	import { prepareChatTools } from './openai-chat-prepare-tools';
