44	type OpenAIChatConfig = {
45	  provider: string;
46	  headers: () => Record<string, string | undefined>;
47	  url: (options: { modelId: string; path: string }) => string;
48	  fetch?: FetchFunction;
49	};
50	
51	export class OpenAIChatLanguageModel implements LanguageModelV3 {
52	  readonly specificationVersion = 'v3';
53	
54	  readonly modelId: OpenAIChatModelId;
55	
56	  readonly supportedUrls = {
57	    'image/*': [/^https?:\/\/.*$/],
58	  };
59	
60	  private readonly config: OpenAIChatConfig;
61	
62	  constructor(modelId: OpenAIChatModelId, config: OpenAIChatConfig) {
63	    this.modelId = modelId;
64	    this.config = config;
65	  }
66	
67	  get provider(): string {
68	    return this.config.provider;
69	  }
70	
71	  private async getArgs({
72	    prompt,
73	    maxOutputTokens,
74	    temperature,
75	    topP,
76	    topK,
77	    frequencyPenalty,
78	    presencePenalty,
79	    stopSequences,
80	    responseFormat,
81	    seed,
82	    tools,
83	    toolChoice,
84	    providerOptions,
85	  }: LanguageModelV3CallOptions) {
86	    const warnings: SharedV3Warning[] = [];
87	
88	    // Parse provider options
89	    const openaiOptions =
90	      (await parseProviderOptions({
91	        provider: 'openai',
92	        providerOptions,
93	        schema: openaiLanguageModelChatOptions,
94	      })) ?? {};
95	
96	    const modelCapabilities = getOpenAILanguageModelCapabilities(this.modelId);
97	    const isReasoningModel =
98	      openaiOptions.forceReasoning ?? modelCapabilities.isReasoningModel;
99	
100	    if (topK != null) {
101	      warnings.push({ type: 'unsupported', feature: 'topK' });
102	    }
103	
104	    const { messages, warnings: messageWarnings } = convertToOpenAIChatMessages(
105	      {
106	        prompt,
107	        systemMessageMode:
108	          openaiOptions.systemMessageMode ??
109	          (isReasoningModel
110	            ? 'developer'
111	            : modelCapabilities.systemMessageMode),
112	      },
113	    );
114	
115	    warnings.push(...messageWarnings);
116	
117	    const strictJsonSchema = openaiOptions.strictJsonSchema ?? true;
118	
119	    const baseArgs = {
120	      // model id:
121	      model: this.modelId,
122	
123	      // model specific settings:
124	      logit_bias: openaiOptions.logitBias,
125	      logprobs:
126	        openaiOptions.logprobs === true ||
127	        typeof openaiOptions.logprobs === 'number'
128	          ? true
129	          : undefined,
130	      top_logprobs:
131	        typeof openaiOptions.logprobs === 'number'
132	          ? openaiOptions.logprobs
133	          : typeof openaiOptions.logprobs === 'boolean'
134	            ? openaiOptions.logprobs
135	              ? 0
136	              : undefined
137	            : undefined,
138	      user: openaiOptions.user,
139	      parallel_tool_calls: openaiOptions.parallelToolCalls,
140	
141	      // standardized settings:
142	      max_tokens: maxOutputTokens,
143	      temperature,
144	      top_p: topP,
145	      frequency_penalty: frequencyPenalty,
146	      presence_penalty: presencePenalty,
147	      response_format:
148	        responseFormat?.type === 'json'
149	          ? responseFormat.schema != null
150	            ? {
151	                type: 'json_schema',
152	                json_schema: {
153	                  schema: responseFormat.schema,
154	                  strict: strictJsonSchema,
155	                  name: responseFormat.name ?? 'response',
156	                  description: responseFormat.description,
157	                },
158	              }
159	            : { type: 'json_object' }
160	          : undefined,
161	      stop: stopSequences,
162	      seed,
163	      verbosity: openaiOptions.textVerbosity,
164	
165	      // openai specific settings:
166	      // TODO AI SDK 6: remove, we auto-map maxOutputTokens now
167	      max_completion_tokens: openaiOptions.maxCompletionTokens,
168	      store: openaiOptions.store,
169	      metadata: openaiOptions.metadata,
170	      prediction: openaiOptions.prediction,
171	      reasoning_effort: openaiOptions.reasoningEffort,
172	      service_tier: openaiOptions.serviceTier,
173	      prompt_cache_key: openaiOptions.promptCacheKey,
174	      prompt_cache_retention: openaiOptions.promptCacheRetention,
175	      safety_identifier: openaiOptions.safetyIdentifier,
176	
177	      // messages:
178	      messages,
179	    };
180	
181	    // remove unsupported settings for reasoning models
182	    // see https://platform.openai.com/docs/guides/reasoning#limitations
183	    if (isReasoningModel) {
184	      // when reasoning effort is none, gpt-5.1 models allow temperature, topP, logprobs
185	      //  https://platform.openai.com/docs/guides/latest-model#gpt-5-1-parameter-compatibility
186	      if (
187	        openaiOptions.reasoningEffort !== 'none' ||
188	        !modelCapabilities.supportsNonReasoningParameters
189	      ) {
190	        if (baseArgs.temperature != null) {
191	          baseArgs.temperature = undefined;
192	          warnings.push({
193	            type: 'unsupported',
194	            feature: 'temperature',
195	            details: 'temperature is not supported for reasoning models',
196	          });
197	        }
198	        if (baseArgs.top_p != null) {
199	          baseArgs.top_p = undefined;
200	          warnings.push({
201	            type: 'unsupported',
202	            feature: 'topP',
203	            details: 'topP is not supported for reasoning models',
204	          });
205	        }
206	        if (baseArgs.logprobs != null) {
207	          baseArgs.logprobs = undefined;
208	          warnings.push({
209	            type: 'other',
210	            message: 'logprobs is not supported for reasoning models',
211	          });
212	        }
213	      }
214	
215	      if (baseArgs.frequency_penalty != null) {
216	        baseArgs.frequency_penalty = undefined;
217	        warnings.push({
218	          type: 'unsupported',
219	          feature: 'frequencyPenalty',
220	          details: 'frequencyPenalty is not supported for reasoning models',
221	        });
222	      }
223	      if (baseArgs.presence_penalty != null) {
224	        baseArgs.presence_penalty = undefined;
225	        warnings.push({
226	          type: 'unsupported',
227	          feature: 'presencePenalty',
228	          details: 'presencePenalty is not supported for reasoning models',
229	        });
230	      }
231	      if (baseArgs.logit_bias != null) {
232	        baseArgs.logit_bias = undefined;
233	        warnings.push({
234	          type: 'other',
235	          message: 'logitBias is not supported for reasoning models',
236	        });
237	      }
238	
239	      if (baseArgs.top_logprobs != null) {
240	        baseArgs.top_logprobs = undefined;
241	        warnings.push({
242	          type: 'other',
243	          message: 'topLogprobs is not supported for reasoning models',
244	        });
245	      }
246	
247	      // reasoning models use max_completion_tokens instead of max_tokens:
248	      if (baseArgs.max_tokens != null) {
249	        if (baseArgs.max_completion_tokens == null) {
250	          baseArgs.max_completion_tokens = baseArgs.max_tokens;
251	        }
252	        baseArgs.max_tokens = undefined;
253	      }
254	    } else if (
255	      this.modelId.startsWith('gpt-4o-search-preview') ||
256	      this.modelId.startsWith('gpt-4o-mini-search-preview')
257	    ) {
258	      if (baseArgs.temperature != null) {
259	        baseArgs.temperature = undefined;
260	        warnings.push({
261	          type: 'unsupported',
262	          feature: 'temperature',
263	          details:
264	            'temperature is not supported for the search preview models and has been removed.',
265	        });
266	      }
267	    }
268	
269	    // Validate flex processing support
270	    if (
271	      openaiOptions.serviceTier === 'flex' &&
272	      !modelCapabilities.supportsFlexProcessing
273	    ) {
274	      warnings.push({
275	        type: 'unsupported',
276	        feature: 'serviceTier',
277	        details:
278	          'flex processing is only available for o3, o4-mini, and gpt-5 models',
279	      });
280	      baseArgs.service_tier = undefined;
281	    }
282	
283	    // Validate priority processing support
284	    if (
285	      openaiOptions.serviceTier === 'priority' &&
286	      !modelCapabilities.supportsPriorityProcessing
287	    ) {
288	      warnings.push({
289	        type: 'unsupported',
290	        feature: 'serviceTier',
291	        details:
292	          'priority processing is only available for supported models (gpt-4, gpt-5, gpt-5-mini, o3, o4-mini) and requires Enterprise access. gpt-5-nano is not supported',
293	      });
294	      baseArgs.service_tier = undefined;
295	    }
296	
297	    const {
298	      tools: openaiTools,
299	      toolChoice: openaiToolChoice,
300	      toolWarnings,
301	    } = prepareChatTools({
302	      tools,
303	      toolChoice,
304	    });
305	
306	    return {
307	      args: {
308	        ...baseArgs,
309	        tools: openaiTools,
310	        tool_choice: openaiToolChoice,
311	      },
312	      warnings: [...warnings, ...toolWarnings],
313	    };
314	  }
315	
316	  async doGenerate(
317	    options: LanguageModelV3CallOptions,
318	  ): Promise<LanguageModelV3GenerateResult> {
319	    const { args: body, warnings } = await this.getArgs(options);
320	
321	    const {
322	      responseHeaders,
323	      value: response,
324	      rawValue: rawResponse,
325	    } = await postJsonToApi({
326	      url: this.config.url({
327	        path: '/chat/completions',
328	        modelId: this.modelId,
329	      }),
330	      headers: combineHeaders(this.config.headers(), options.headers),
331	      body,
332	      failedResponseHandler: openaiFailedResponseHandler,
333	      successfulResponseHandler: createJsonResponseHandler(
334	        openaiChatResponseSchema,
335	      ),
336	      abortSignal: options.abortSignal,
337	      fetch: this.config.fetch,
338	    });
339	
340	    const choice = response.choices[0];
341	    const content: Array<LanguageModelV3Content> = [];
342	
343	    // text content:
344	    const text = choice.message.content;
345	    if (text != null && text.length > 0) {
346	      content.push({ type: 'text', text });
347	    }
348	
349	    // tool calls:
350	    for (const toolCall of choice.message.tool_calls ?? []) {
351	      content.push({
352	        type: 'tool-call' as const,
353	        toolCallId: toolCall.id ?? generateId(),
354	        toolName: toolCall.function.name,
355	        input: toolCall.function.arguments!,
356	      });
357	    }
358	
359	    // annotations/citations:
360	    for (const annotation of choice.message.annotations ?? []) {
361	      content.push({
362	        type: 'source',
363	        sourceType: 'url',
364	        id: generateId(),
365	        url: annotation.url_citation.url,
366	        title: annotation.url_citation.title,
367	      });
368	    }
369	
370	    // provider metadata:
371	    const completionTokenDetails = response.usage?.completion_tokens_details;
