404	  async doStream(
405	    options: LanguageModelV3CallOptions,
406	  ): Promise<LanguageModelV3StreamResult> {
407	    const { args, warnings } = await this.getArgs(options);
408	
409	    const body = {
410	      ...args,
411	      stream: true,
412	      stream_options: {
413	        include_usage: true,
414	      },
415	    };
416	
417	    const { responseHeaders, value: response } = await postJsonToApi({
418	      url: this.config.url({
419	        path: '/chat/completions',
420	        modelId: this.modelId,
421	      }),
422	      headers: combineHeaders(this.config.headers(), options.headers),
423	      body,
424	      failedResponseHandler: openaiFailedResponseHandler,
425	      successfulResponseHandler: createEventSourceResponseHandler(
426	        openaiChatChunkSchema,
427	      ),
428	      abortSignal: options.abortSignal,
429	      fetch: this.config.fetch,
430	    });
431	
432	    const toolCalls: Array<{
433	      id: string;
434	      type: 'function';
435	      function: {
436	        name: string;
437	        arguments: string;
438	      };
439	      hasFinished: boolean;
440	    }> = [];
441	
442	    let finishReason: LanguageModelV3FinishReason = {
443	      unified: 'other',
444	      raw: undefined,
445	    };
446	    let usage: OpenAIChatUsage | undefined = undefined;
447	    let metadataExtracted = false;
448	    let isActiveText = false;
449	
450	    const providerMetadata: SharedV3ProviderMetadata = { openai: {} };
451	
452	    return {
453	      stream: response.pipeThrough(
454	        new TransformStream<
455	          ParseResult<OpenAIChatChunk>,
456	          LanguageModelV3StreamPart
457	        >({
458	          start(controller) {
459	            controller.enqueue({ type: 'stream-start', warnings });
460	          },
461	
462	          transform(chunk, controller) {
463	            if (options.includeRawChunks) {
464	              controller.enqueue({ type: 'raw', rawValue: chunk.rawValue });
465	            }
466	
467	            // handle failed chunk parsing / validation:
468	            if (!chunk.success) {
469	              finishReason = { unified: 'error', raw: undefined };
470	              controller.enqueue({ type: 'error', error: chunk.error });
471	              return;
472	            }
473	
474	            const value = chunk.value;
475	
476	            // handle error chunks:
477	            if ('error' in value) {
478	              finishReason = { unified: 'error', raw: undefined };
479	              controller.enqueue({ type: 'error', error: value.error });
480	              return;
481	            }
482	
483	            // extract and emit response metadata once. Usually it comes in the first chunk.
484	            // Azure may prepend a chunk with a `"prompt_filter_results"` key which does not contain other metadata,
485	            // https://learn.microsoft.com/en-us/azure/ai-foundry/openai/concepts/content-filter-annotations?tabs=powershell
486	            if (!metadataExtracted) {
487	              const metadata = getResponseMetadata(value);
488	              if (Object.values(metadata).some(Boolean)) {
489	                metadataExtracted = true;
490	                controller.enqueue({
491	                  type: 'response-metadata',
492	                  ...getResponseMetadata(value),
493	                });
494	              }
495	            }
496	
497	            if (value.usage != null) {
498	              usage = value.usage;
499	
500	              if (
501	                value.usage.completion_tokens_details
502	                  ?.accepted_prediction_tokens != null
503	              ) {
504	                providerMetadata.openai.acceptedPredictionTokens =
505	                  value.usage.completion_tokens_details?.accepted_prediction_tokens;
506	              }
507	              if (
508	                value.usage.completion_tokens_details
509	                  ?.rejected_prediction_tokens != null
510	              ) {
511	                providerMetadata.openai.rejectedPredictionTokens =
512	                  value.usage.completion_tokens_details?.rejected_prediction_tokens;
513	              }
514	            }
515	
516	            const choice = value.choices[0];
517	
518	            if (choice?.finish_reason != null) {
519	              finishReason = {
520	                unified: mapOpenAIFinishReason(choice.finish_reason),
521	                raw: choice.finish_reason,
522	              };
523	            }
524	
525	            if (choice?.logprobs?.content != null) {
526	              providerMetadata.openai.logprobs = choice.logprobs.content;
527	            }
528	
529	            if (choice?.delta == null) {
530	              return;
531	            }
532	
533	            const delta = choice.delta;
534	
535	            if (delta.content != null) {
536	              if (!isActiveText) {
537	                controller.enqueue({ type: 'text-start', id: '0' });
538	                isActiveText = true;
539	              }
540	
541	              controller.enqueue({
542	                type: 'text-delta',
543	                id: '0',
544	                delta: delta.content,
545	              });
546	            }
547	
548	            if (delta.tool_calls != null) {
549	              for (const toolCallDelta of delta.tool_calls) {
550	                const index = toolCallDelta.index;
551	
552	                // Tool call start. OpenAI returns all information except the arguments in the first chunk.
553	                if (toolCalls[index] == null) {
554	                  if (
555	                    toolCallDelta.type != null &&
556	                    toolCallDelta.type !== 'function'
557	                  ) {
558	                    throw new InvalidResponseDataError({
559	                      data: toolCallDelta,
560	                      message: `Expected 'function' type.`,
561	                    });
562	                  }
563	
564	                  if (toolCallDelta.id == null) {
565	                    throw new InvalidResponseDataError({
566	                      data: toolCallDelta,
567	                      message: `Expected 'id' to be a string.`,
568	                    });
569	                  }
570	
571	                  if (toolCallDelta.function?.name == null) {
572	                    throw new InvalidResponseDataError({
573	                      data: toolCallDelta,
574	                      message: `Expected 'function.name' to be a string.`,
575	                    });
576	                  }
577	
578	                  controller.enqueue({
579	                    type: 'tool-input-start',
580	                    id: toolCallDelta.id,
581	                    toolName: toolCallDelta.function.name,
582	                  });
583	
584	                  toolCalls[index] = {
585	                    id: toolCallDelta.id,
586	                    type: 'function',
587	                    function: {
588	                      name: toolCallDelta.function.name,
589	                      arguments: toolCallDelta.function.arguments ?? '',
590	                    },
591	                    hasFinished: false,
592	                  };
593	
594	                  const toolCall = toolCalls[index];
595	
596	                  if (
597	                    toolCall.function?.name != null &&
598	                    toolCall.function?.arguments != null
599	                  ) {
600	                    // send delta if the argument text has already started:
601	                    if (toolCall.function.arguments.length > 0) {
602	                      controller.enqueue({
603	                        type: 'tool-input-delta',
604	                        id: toolCall.id,
605	                        delta: toolCall.function.arguments,
606	                      });
607	                    }
608	
609	                    // check if tool call is complete
610	                    // (some providers send the full tool call in one chunk):
611	                    if (isParsableJson(toolCall.function.arguments)) {
612	                      controller.enqueue({
613	                        type: 'tool-input-end',
614	                        id: toolCall.id,
615	                      });
616	
617	                      controller.enqueue({
618	                        type: 'tool-call',
619	                        toolCallId: toolCall.id ?? generateId(),
620	                        toolName: toolCall.function.name,
621	                        input: toolCall.function.arguments,
622	                      });
623	                      toolCall.hasFinished = true;
624	                    }
625	                  }
626	
627	                  continue;
628	                }
629	
630	                // existing tool call, merge if not finished
631	                const toolCall = toolCalls[index];
632	
633	                if (toolCall.hasFinished) {
634	                  continue;
635	                }
636	
637	                if (toolCallDelta.function?.arguments != null) {
638	                  toolCall.function!.arguments +=
639	                    toolCallDelta.function?.arguments ?? '';
640	                }
641	
642	                // send delta
643	                controller.enqueue({
644	                  type: 'tool-input-delta',
645	                  id: toolCall.id,
646	                  delta: toolCallDelta.function.arguments ?? '',
647	                });
648	
649	                // check if tool call is complete
650	                if (
651	                  toolCall.function?.name != null &&
652	                  toolCall.function?.arguments != null &&
653	                  isParsableJson(toolCall.function.arguments)
654	                ) {
655	                  controller.enqueue({
656	                    type: 'tool-input-end',
657	                    id: toolCall.id,
658	                  });
659	
660	                  controller.enqueue({
661	                    type: 'tool-call',
662	                    toolCallId: toolCall.id ?? generateId(),
663	                    toolName: toolCall.function.name,
664	                    input: toolCall.function.arguments,
665	                  });
666	                  toolCall.hasFinished = true;
667	                }
668	              }
669	            }
670	
671	            // annotations/citations:
672	            if (delta.annotations != null) {
673	              for (const annotation of delta.annotations) {
674	                controller.enqueue({
675	                  type: 'source',
676	                  sourceType: 'url',
677	                  id: generateId(),
678	                  url: annotation.url_citation.url,
679	                  title: annotation.url_citation.title,
680	                });
681	              }
682	            }
683	          },
684	
685	          flush(controller) {
686	            if (isActiveText) {
687	              controller.enqueue({ type: 'text-end', id: '0' });
688	            }
689	
690	            controller.enqueue({
691	              type: 'finish',
692	              finishReason,
693	              usage: convertOpenAIChatUsage(usage),
694	              ...(providerMetadata != null ? { providerMetadata } : {}),
695	            });
696	          },
697	        }),
698	      ),
699	      request: { body },
700	      response: { headers: responseHeaders },
701	    };
702	  }
703	}
