7	export type ResponseHandler<RETURN_TYPE> = (options: {
8	  url: string;
9	  requestBodyValues: unknown;
10	  response: Response;
11	}) => PromiseLike<{
12	  value: RETURN_TYPE;
13	  rawValue?: unknown;
14	  responseHeaders?: Record<string, string>;
