**Factory Function:**
```typescript
export function createOpenAI(options: OpenAIProviderSettings = {}): OpenAIProvider {
  // 1. Load configuration from options/environment
  const baseURL = withoutTrailingSlash(
    loadOptionalSetting({
      settingValue: options.baseURL,
      environmentVariableName: 'OPENAI_BASE_URL',
    })
  ) ?? 'https://api.openai.com/v1';

  const providerName = options.name ?? 'openai';

  // 2. Setup header factory
  const getHeaders = () =>
    withUserAgentSuffix({
      Authorization: `Bearer ${loadApiKey({...})}`,
      'OpenAI-Organization': options.organization,
      'OpenAI-Project': options.project,
      ...options.headers,
    }, `ai-sdk/openai/${VERSION}`);

  // 3. Create individual model factories
  const createChatModel = (modelId: OpenAIChatModelId) =>
    new OpenAIChatLanguageModel(modelId, { 
      provider: `${providerName}.chat`,
      url: ({ path }) => `${baseURL}${path}`,
      headers: getHeaders,
      fetch: options.fetch,
    });

  // Similar factories for: completion, embedding, image, transcription, speech

  // 4. Assemble provider instance
  const provider = function (modelId: OpenAIResponsesModelId) {
    return createLanguageModel(modelId);
  };

  provider.specificationVersion = 'v3';
  provider.languageModel = createLanguageModel;
  provider.chat = createChatModel;
  provider.completion = createCompletionModel;
  // ... attach all model factories
  provider.tools = openaiTools;

  return provider as OpenAIProvider;
}

// Export default instance
export const openai = createOpenAI();
```

**Key design features:**
- **Lazy configuration:** Headers/URLs computed via closures to access fresh environment variables
- **Configurable provider name:** Allows OpenAI-compatible services to override identity
- **Custom fetch support:** Enables middleware patterns and testing
- **Model-specific namespaces:** `provider.chat()`, `provider.embedding()`, etc.
- **Unified interface:** All models accessible via functional or method syntax

