### 8. IMPLEMENTATION PATTERN

**Minimal example of a custom image model:**

```typescript
import { ImageModelV3, ImageModelV3CallOptions, SharedV3Warning } from '@ai-sdk/provider';

export class CustomImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3' as const;
  readonly provider = 'custom-provider';
  readonly modelId: string;
  readonly maxImagesPerCall = 4;

  constructor(modelId: string) {
    this.modelId = modelId;
  }

  async doGenerate(options: ImageModelV3CallOptions): Promise<{
    images: Array<string | Uint8Array>;
    warnings: Array<SharedV3Warning>;
    response: {
      timestamp: Date;
      modelId: string;
      headers: Record<string, string> | undefined;
    };
    providerMetadata?: Record<string, any>;
    usage?: { inputTokens?: number; outputTokens?: number; totalTokens?: number };
  }> {
    const warnings: Array<SharedV3Warning> = [];

    // Validate unsupported features
    if (options.seed != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'seed',
      });
    }

    // Make API call
    const response = await fetch('https://api.custom.com/generate', {
      method: 'POST',
      headers: options.headers,
      body: JSON.stringify({
        prompt: options.prompt,
        num_images: options.n,
        size: options.size,
        ...options.providerOptions.customProvider,
      }),
      signal: options.abortSignal,
    });

    const data = await response.json();

    return {
      images: data.images, // base64 strings or Uint8Array
      warnings,
      response: {
        timestamp: new Date(),
        modelId: this.modelId,
        headers: Object.fromEntries(response.headers.entries()),
      },
      providerMetadata: {
        customProvider: {
          images: data.images.map((img, i) => ({
            seed: data.seeds?.[i],
          })),
        },
      },
    };
  }
}
```

