// this approach limits breakages when the API changes and increases efficiency
const pixelartImageResponseSchema = lazySchema(() =>
  zodSchema(
    z.object({
      data: z.array(
        z.object({
          b64_json: z.string(),
        }),
      ),
    }),
  ),
);

const pixelartErrorSchema = z.object({
  error: z.object({
    message: z.string(),
    type: z.string().nullish(),
    code: z.string().nullish(),
  }),
});

export type PixelArtErrorData = z.infer<typeof pixelartErrorSchema>;

const pixelartFailedResponseHandler = createJsonErrorResponseHandler({
  errorSchema: pixelartErrorSchema,
  errorToMessage: (error: PixelArtErrorData) => error.error.message,
});

/**
 * Provider options schema for PixelArt image generation.
 */
export const pixelartImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z.object({
      /**
       * The style of pixel art to generate.
       *
       * - `pixel`: Classic pixel art style with visible square pixels.
       * - `retro`: Retro gaming aesthetic with limited color palette.
       * - `8bit`: 8-bit era style with characteristic chunky graphics.
       */
      style: z.enum(['pixel', 'retro', '8bit']).nullish(),

      /**
       * The density of pixels in the generated image. Higher values produce
       * finer detail within the pixel art style.
       *
       * Typical range: 1-10.
       */
      pixelDensity: z.number().nullish(),
    }),
  ),
);

export type PixelArtImageModelOptions = InferSchema<
  typeof pixelartImageModelOptionsSchema
>;

